#include <iostream>
using namespace std;
int main()
{
    int n;
    cin >> n;
    int x1[n], y1[n], x2[n], y2[n];
    for (int i = 0; i < n; i++)
    {
        cin >> x1[i] >> y1[i] >> x2[i] >> y2[i];
    }
    int xmin = x1[0], xmax = x2[0], ymin = y1[0], ymax = y2[0];
    for (int i = 0; i < n; i++)
    {
        xmin = min(xmin, x1[i]);
        xmax = max(xmax, x2[i]);
        ymin = min(ymin, y1[i]);
        ymax = max(ymax, y2[i]);
    }
    if (xmax - xmin == ymax - ymin)
    {
        cout << "YES" << endl;
    }
    else
    {
        cout << "NO" << endl;
    }
    return 0;
}
